pub const RBTDRM_COLOPHON_ABJURE: &str = "rbw-fA";
pub const RBTDRM_COLOPHON_TALLY: &str = "rbw-ft";
pub const RBTDRM_COLOPHON_KLUDGE: &str = "rbw-fk";
